<script setup lang="ts">
import { PropType, computed, ref, watch } from 'vue'
import { useForm } from 'vuestic-ui'
import { Promoter, UserOption } from '../types'

const props = defineProps({
    promoter: {
        type: Object as PropType<Promoter | null>,
        default: null,
    },
    users: {
        type: Array as PropType<UserOption[]>,
        default: () => [],
    },
    saveButtonLabel: {
        type: String,
        default: '儲存',
    },
})

const selectedUserId = ref<number | null>(props.promoter?.userId ?? null)
const status = ref<'active' | 'inactive'>(props.promoter?.status ?? 'active')

const isFormHasUnsavedChanges = computed(() => {
    if (props.promoter) {
        return selectedUserId.value !== props.promoter.userId || status.value !== props.promoter.status
    }
    return selectedUserId.value !== null
})

defineExpose({
    isFormHasUnsavedChanges,
})

watch(
    () => props.promoter,
    (newVal) => {
        if (newVal) {
            selectedUserId.value = newVal.userId
            status.value = newVal.status
        } else {
            selectedUserId.value = null
            status.value = 'active'
        }
    },
    { immediate: true },
)

// 為下拉選單建立選項
const userOptions = computed(() => {
    return props.users.map((user) => {
        const displayName =
            user.nickname || `${user.firstName || ''} ${user.lastName || ''}`.trim() || user.email || `User #${user.id}`
        return {
            text: `${displayName} (${user.email || ''})`,
            value: user.id,
        }
    })
})

const form = useForm('edit-promoter-form')

const emit = defineEmits<{
    close: []
    save: [data: { userId: number; status: 'active' | 'inactive' }]
}>()

const onSave = () => {
    if (!form.validate()) return
    if (!selectedUserId.value) return

    emit('save', {
        userId: selectedUserId.value,
        status: status.value,
    })
}
</script>

<template>
    <VaForm ref="edit-promoter-form" class="flex flex-col gap-4 w-full">
        <VaSelect
            v-model="selectedUserId"
            label="帳號"
            :options="userOptions"
            :rules="[(v: any) => !!v || '請選擇帳號']"
            value-by="value"
            text-by="text"
            placeholder="請選擇帳號"
            :disabled="!!promoter"
            searchable
        />

        <VaSwitch v-model="status" true-value="active" false-value="inactive" label="啟用狀態" />

        <div class="flex gap-2 flex-col-reverse sm:flex-row mt-4 justify-end">
            <VaButton preset="secondary" color="secondary" @click="$emit('close')">取消</VaButton>
            <VaButton @click="onSave">{{ saveButtonLabel }}</VaButton>
        </div>
    </VaForm>
</template>
