import { Ref, ref, watch } from 'vue'
import { Promoter, CreatePromoterRequest, UpdatePromoterRequest, UserOption } from '../types'
import { watchIgnorable } from '@vueuse/core'
import api from '../../../services/api'

export type Pagination = {
    page: number
    perPage: number
    total: number
}

export type Sorting = {
    sortBy: keyof Promoter | undefined
    sortingOrder: 'asc' | 'desc' | null
}

export type Filters = {
    status: 'active' | 'inactive' | ''
}

const makePaginationRef = () => ref<Pagination>({ page: 1, perPage: 10, total: 0 })
const makeSortingRef = () => ref<Sorting>({ sortBy: 'id', sortingOrder: null })
const makeFiltersRef = () => ref<Partial<Filters>>({ status: '' })

export const usePromoters = (options?: {
    pagination?: Ref<Pagination>
    sorting?: Ref<Sorting>
    filters?: Ref<Partial<Filters>>
}) => {
    const isLoading = ref(false)
    const promoters = ref<Promoter[]>([])
    const users = ref<UserOption[]>([])

    const { filters = makeFiltersRef(), sorting = makeSortingRef(), pagination = makePaginationRef() } = options || {}

    const fetchUsers = async () => {
        try {
            const { data } = await api.axiosInstance.get('/user')
            users.value = data.data
        } catch (error) {
            console.error('Error fetching users:', error)
        }
    }

    const getUserDisplayName = (userId: number): string => {
        const user = users.value.find((u) => u.id === userId)
        if (!user) return `User #${userId}`
        if (user.nickname) return user.nickname
        if (user.firstName || user.lastName) return `${user.firstName || ''} ${user.lastName || ''}`.trim()
        return user.email || `User #${userId}`
    }

    const getUserEmail = (userId: number): string => {
        const user = users.value.find((u) => u.id === userId)
        return user?.email || ''
    }

    const fetch = async () => {
        isLoading.value = true
        try {
            const params: Record<string, any> = {
                page: pagination.value.page,
                limit: pagination.value.perPage,
            }
            if (filters.value.status) {
                params.status = filters.value.status
            }

            const { data } = await api.axiosInstance.get('/affiliate/promoter', { params })
            const rawPromoters = data.data as Promoter[]

            // join user info
            promoters.value = rawPromoters.map((p) => ({
                ...p,
                userName: getUserDisplayName(p.userId),
                userEmail: getUserEmail(p.userId),
            }))

            ignoreUpdates(() => {
                pagination.value = {
                    page: data.page || pagination.value.page,
                    perPage: data.limit || pagination.value.perPage,
                    total: data.total || 0,
                }
            })
        } catch (error) {
            console.error('Error fetching promoters:', error)
        } finally {
            isLoading.value = false
        }
    }

    const { ignoreUpdates } = watchIgnorable([pagination, sorting], fetch, { deep: true })

    watch(
        filters,
        () => {
            pagination.value.page = 1
            fetch()
        },
        { deep: true },
    )

    // 初始化：先取使用者清單，再取推廣者列表
    const init = async () => {
        await fetchUsers()
        await fetch()
    }

    init()

    return {
        isLoading,
        filters,
        sorting,
        pagination,
        promoters,
        users,
        fetch,
        fetchUsers,
        getUserDisplayName,
        getUserEmail,

        async add(request: CreatePromoterRequest) {
            isLoading.value = true
            try {
                await api.axiosInstance.post('/affiliate/promoter', request)
                await fetch()
            } catch (error) {
                console.error('Error adding promoter:', error)
                throw error
            } finally {
                isLoading.value = false
            }
        },

        async updateStatus(request: UpdatePromoterRequest) {
            isLoading.value = true
            try {
                const { id, ...body } = request
                await api.axiosInstance.patch(`/affiliate/promoter/${id}`, body)
                await fetch()
            } catch (error) {
                console.error('Error updating promoter:', error)
                throw error
            } finally {
                isLoading.value = false
            }
        },

        async toggleStatus(promoter: Promoter) {
            const newStatus = promoter.status === 'active' ? 'inactive' : 'active'
            await this.updateStatus({ id: promoter.id, status: newStatus })
        },
    }
}
