<script setup lang="ts">
import { defineVaDataTableColumns, useModal } from 'vuestic-ui'
import { Promoter } from '../types'
import { PropType, computed, toRef } from 'vue'
import { Pagination, Sorting } from '../composables/usePromoters'
import { useVModel } from '@vueuse/core'
import { useFormat } from '../../../composables/useFormat'
const columns = defineVaDataTableColumns([
    { label: '推廣夥伴名稱', key: 'userName', sortable: true },
    { label: '帳號', key: 'userEmail', sortable: true },
    { label: '狀態', key: 'status' },
    { label: '建立日期', key: 'createdAt', sortable: true },
    { label: '操作', key: 'actions', align: 'right' },
])

const props = defineProps({
    promoters: {
        type: Array as PropType<Promoter[]>,
        required: true,
    },
    loading: { type: Boolean, default: false },
    pagination: { type: Object as PropType<Pagination>, required: true },
    sortBy: { type: String as PropType<Sorting['sortBy']>, required: true },
    sortingOrder: { type: String as PropType<Sorting['sortingOrder']>, required: true },
})

const emit = defineEmits<{
    (event: 'editPromoter', promoter: Promoter): void
    (event: 'deletePromoter', promoter: Promoter): void
    (event: 'toggleStatus', promoter: Promoter): void
    (event: 'update:sortBy', sortBy: Sorting['sortBy']): void
    (event: 'update:sortingOrder', sortingOrder: Sorting['sortingOrder']): void
}>()

const promoters = toRef(props, 'promoters')
const sortByVModel = useVModel(props, 'sortBy', emit)
const sortingOrderVModel = useVModel(props, 'sortingOrder', emit)

const totalPages = computed(() => Math.ceil(props.pagination.total / props.pagination.perPage))

const { confirm } = useModal()

const onPromoterDelete = async (promoter: Promoter) => {
    const agreed = await confirm({
        title: '刪除推廣夥伴',
        message: `確定要刪除 ${promoter.userName || ''} 嗎？`,
        okText: '刪除',
        cancelText: '取消',
        size: 'small',
        maxWidth: '380px',
    })

    if (agreed) {
        emit('deletePromoter', promoter)
    }
}

const { formatDate } = useFormat()
</script>

<template>
    <VaDataTable
        v-model:sort-by="sortByVModel"
        v-model:sorting-order="sortingOrderVModel"
        :columns="columns"
        :items="promoters"
        :loading="$props.loading"
    >
        <template #cell(userName)="{ rowData }">
            <div class="font-semibold max-w-[230px] ellipsis">
                {{ rowData.userName }}
            </div>
        </template>

        <template #cell(userEmail)="{ rowData }">
            <div class="max-w-[250px] ellipsis">
                {{ rowData.userEmail }}
            </div>
        </template>

        <template #cell(status)="{ rowData }">
            <VaSwitch
                :model-value="rowData.status === 'active'"
                size="small"
                @update:modelValue="$emit('toggleStatus', rowData as Promoter)"
            />
        </template>

        <template #cell(createdAt)="{ rowData }">
            {{ formatDate(Number(rowData.createdAt)) }}
        </template>

        <template #cell(actions)="{ rowData }">
            <div class="flex gap-2 justify-end">
                <VaButton
                    preset="primary"
                    size="small"
                    icon="mso-edit"
                    aria-label="編輯推廣夥伴"
                    @click="$emit('editPromoter', rowData as Promoter)"
                />
                <VaButton
                    preset="primary"
                    size="small"
                    icon="mso-delete"
                    color="danger"
                    aria-label="刪除推廣夥伴"
                    @click="onPromoterDelete(rowData as Promoter)"
                />
            </div>
        </template>
    </VaDataTable>

    <div class="flex flex-col-reverse md:flex-row gap-2 justify-between items-center py-2">
        <div>
            <b>{{ $props.pagination.total }} results.</b>
            Results per page
            <VaSelect v-model="$props.pagination.perPage" class="!w-20" :options="[10, 50, 100]" />
        </div>

        <div v-if="totalPages > 1" class="flex">
            <VaButton
                preset="secondary"
                icon="va-arrow-left"
                aria-label="Previous page"
                :disabled="$props.pagination.page === 1"
                @click="$props.pagination.page--"
            />
            <VaButton
                class="mr-2"
                preset="secondary"
                icon="va-arrow-right"
                aria-label="Next page"
                :disabled="$props.pagination.page === totalPages"
                @click="$props.pagination.page++"
            />
            <VaPagination
                v-model="$props.pagination.page"
                buttons-preset="secondary"
                :pages="totalPages"
                :visible-pages="5"
                :boundary-links="false"
                :direction-links="false"
            />
        </div>
    </div>
</template>

<style lang="scss" scoped>
.va-data-table {
    ::v-deep(.va-data-table__table-tr) {
        border-bottom: 1px solid var(--va-background-border);
    }
}
</style>
