<script setup lang="ts">
import { ref } from 'vue'
import PromotersTable from './widgets/PromotersTable.vue'
import EditPromoterForm from './widgets/EditPromoterForm.vue'
import { Promoter } from './types'
import { usePromoters } from './composables/usePromoters'
import { useModal, useToast } from 'vuestic-ui'
const doShowEditPromoterModal = ref(false)

const { promoters, isLoading, filters, sorting, pagination, users, ...promotersApi } = usePromoters()

const promoterToEdit = ref<Promoter | null>(null)

const showEditPromoterModal = (promoter: Promoter) => {
    promoterToEdit.value = promoter
    doShowEditPromoterModal.value = true
}

const showAddPromoterModal = () => {
    promoterToEdit.value = null
    doShowEditPromoterModal.value = true
}

const { init: notify } = useToast()

const onPromoterSaved = async (data: { userId: number; status: 'active' | 'inactive' }) => {
    try {
        if (promoterToEdit.value) {
            await promotersApi.updateStatus({ id: promoterToEdit.value.id, status: data.status })
            notify({
                message: '推廣夥伴已更新',
                color: 'success',
            })
        } else {
            await promotersApi.add({ userId: data.userId, status: data.status })
            notify({
                message: '推廣夥伴已建立',
                color: 'success',
            })
        }
    } catch (error) {
        notify({
            message: '操作失敗，請再試一次',
            color: 'danger',
        })
    }
}

const onToggleStatus = async (promoter: Promoter) => {
    try {
        const newStatus = promoter.status === 'active' ? 'inactive' : 'active'
        await promotersApi.updateStatus({ id: promoter.id, status: newStatus })
        notify({
            message: `${promoter.userName || ''} 狀態已更新`,
            color: 'success',
        })
    } catch (error) {
        notify({
            message: '狀態更新失敗',
            color: 'danger',
        })
    }
}

const onPromoterDelete = async (promoter: Promoter) => {
    // 目前 API 無刪除推廣者端點，以停用代替
    try {
        await promotersApi.updateStatus({ id: promoter.id, status: 'inactive' })
        notify({
            message: `${promoter.userName || ''} 已停用`,
            color: 'success',
        })
    } catch (error) {
        notify({
            message: '操作失敗',
            color: 'danger',
        })
    }
}

const editFormRef = ref()

const { confirm } = useModal()

const beforeEditFormModalClose = async (hide: () => unknown) => {
    if (editFormRef.value?.isFormHasUnsavedChanges) {
        const agreed = await confirm({
            maxWidth: '380px',
            message: '表單有未儲存的變更，確定要關閉嗎？',
            size: 'small',
        })
        if (agreed) {
            hide()
        }
    } else {
        hide()
    }
}
</script>

<template>
    <h1 class="page-title">推廣夥伴管理</h1>

    <VaCard>
        <VaCardContent>
            <div class="flex flex-col md:flex-row gap-2 mb-2 justify-between">
                <div class="flex flex-col md:flex-row gap-2 justify-start">
                    <VaButtonToggle
                        v-model="filters.status"
                        color="background-element"
                        border-color="background-element"
                        :options="[
                            { label: '全部', value: '' },
                            { label: '啟用中', value: 'active' },
                            { label: '已停用', value: 'inactive' },
                        ]"
                    />
                </div>
                <VaButton @click="showAddPromoterModal">新增推廣夥伴</VaButton>
            </div>

            <PromotersTable
                v-model:sort-by="sorting.sortBy"
                v-model:sorting-order="sorting.sortingOrder"
                :promoters="promoters"
                :loading="isLoading"
                :pagination="pagination"
                @editPromoter="showEditPromoterModal"
                @deletePromoter="onPromoterDelete"
                @toggleStatus="onToggleStatus"
            />
        </VaCardContent>
    </VaCard>

    <VaModal
        v-slot="{ cancel, ok }"
        v-model="doShowEditPromoterModal"
        size="small"
        mobile-fullscreen
        close-button
        hide-default-actions
        :before-cancel="beforeEditFormModalClose"
    >
        <h1 class="va-h5">{{ promoterToEdit ? '編輯推廣夥伴' : '新增推廣夥伴' }}</h1>
        <EditPromoterForm
            ref="editFormRef"
            :promoter="promoterToEdit"
            :users="users"
            :save-button-label="promoterToEdit ? '儲存' : '新增'"
            @close="cancel"
            @save="
                (data) => {
                    onPromoterSaved(data)
                    ok()
                }
            "
        />
    </VaModal>
</template>
